(async function () {
    'use strict';

    const TARGET_API = '/api/backends/chat-completions/generate';
    const STORAGE_KEY = 'stc-monitor-config';
    const DB_NAME = 'StCacheMonitorDB';
    const DB_VERSION = 1;

    // ==================== 樱花主题 ====================
    const THEMES = {
        dark: {
            name: '深粉',
            icon: '🌸',
            "--stc-bg": "rgba(18, 14, 16, 0.96)",
            "--stc-bg-sec": "rgba(28, 22, 25, 0.98)",
            "--stc-accent": "#ffa5c0",
            "--stc-text": "#fff0f5",
            "--stc-text-sec": "#e6ccd8",
            "--stc-danger": "#ff7b7b",
            "--stc-border": "rgba(255, 165, 192, 0.5)",
            "--stc-hit": "#ff8cb0",
            "--stc-miss": "#ffb085",
            "--stc-hit-bottom": "#ff6f91",
            "--stc-miss-bottom": "#ff8c42",
            "--stc-shadow": "0 8px 32px rgba(0, 0, 0, 0.6)"
        },
        light: {
            name: '淡粉',
            icon: '🌸',
            "--stc-bg": "rgba(255, 250, 251, 0.96)",
            "--stc-bg-sec": "rgba(255, 245, 247, 0.98)",
            "--stc-accent": "#e86f8c",
            "--stc-text": "#3c2c32",
            "--stc-text-sec": "#8b6b78",
            "--stc-danger": "#d9534f",
            "--stc-border": "rgba(232, 111, 140, 0.4)",
            "--stc-hit": "#d95b7a",
            "--stc-miss": "#e68a5e",
            "--stc-hit-bottom": "#e86f8c",
            "--stc-miss-bottom": "#e68a5e",
            "--stc-shadow": "0 8px 32px rgba(160, 100, 120, 0.2)"
        }
    };

    let savedConfig = {
        panelLeft: '70px',
        panelTop: '20px',
        panelWidth: '340px',
        panelHeight: '480px',
        bubbleTop: '20vh',
        bubbleSide: 'left',
        isMinimized: true,
        theme: 'light'
    };

    // 顶层窗口（兼容iframe跨域）
    let topWindow, topDoc;
    try {
        topWindow = (window.parent !== window) ? window.parent : window;
        topDoc = topWindow.document;
    } catch (e) {
        topWindow = window;
        topDoc = document;
    }

    // ==================== IndexedDB ====================
    function openDB() {
        return new Promise((resolve, reject) => {
            const request = indexedDB.open(DB_NAME, DB_VERSION);
            request.onerror = () => reject(request.error);
            request.onsuccess = () => resolve(request.result);
            request.onupgradeneeded = (event) => {
                const db = event.target.result;
                if (!db.objectStoreNames.contains('config')) db.createObjectStore('config', { keyPath: 'key' });
                if (!db.objectStoreNames.contains('cacheData')) {
                    const store = db.createObjectStore('cacheData', { keyPath: 'requestId' });
                    store.createIndex('timestamp', 'timestamp', { unique: false });
                }
            };
        });
    }

    async function saveToDB(storeName, data) {
        const db = await openDB();
        return new Promise((resolve) => {
            const transaction = db.transaction(storeName, 'readwrite');
            transaction.objectStore(storeName).put(data);
            transaction.oncomplete = () => { db.close(); resolve(); };
        });
    }

    async function getFromDB(storeName, key) {
        const db = await openDB();
        return new Promise((resolve) => {
            const request = db.transaction(storeName, 'readonly').objectStore(storeName).get(key);
            request.onsuccess = () => { db.close(); resolve(request.result); };
        });
    }

    async function getAllFromDB(storeName) {
        const db = await openDB();
        return new Promise((resolve) => {
            const request = db.transaction(storeName, 'readonly').objectStore(storeName).getAll();
            request.onsuccess = () => { db.close(); resolve(request.result); };
        });
    }

    async function clearStore(storeName) {
        const db = await openDB();
        const transaction = db.transaction(storeName, 'readwrite');
        transaction.objectStore(storeName).clear();
        return new Promise(r => transaction.oncomplete = () => { db.close(); r(); });
    }

    // ==================== 配置 ====================
    async function initConfig() {
        try {
            const dbConfig = await getFromDB('config', STORAGE_KEY);
            if (dbConfig && dbConfig.value) savedConfig = { ...savedConfig, ...dbConfig.value };
        } catch (e) { }
    }

    async function saveConfig(overrides = {}) {
        savedConfig = { ...savedConfig, ...overrides };
        await saveToDB('config', { key: STORAGE_KEY, value: savedConfig });
    }

    // ==================== 边界钳位 ====================
    function clampPanelToViewport(panel) {
        if (!panel || panel.style.display !== 'flex') return;
        const rect = panel.getBoundingClientRect();
        const winW = topWindow.innerWidth;
        const winH = topWindow.innerHeight;
        let newLeft = rect.left, newTop = rect.top;
        const margin = 10;
        if (rect.right > winW - margin) newLeft = winW - rect.width - margin;
        if (rect.left < margin) newLeft = margin;
        if (rect.bottom > winH - margin) newTop = winH - rect.height - margin;
        if (rect.top < margin) newTop = margin;
        if (newLeft !== rect.left) panel.style.left = newLeft + 'px';
        if (newTop !== rect.top) panel.style.top = newTop + 'px';
        saveConfig({ panelLeft: panel.style.left, panelTop: panel.style.top });
    }

    function clampBubbleToViewport(bubble) {
        if (!bubble) return;
        const rect = bubble.getBoundingClientRect();
        const winW = topWindow.innerWidth;
        const winH = topWindow.innerHeight;
        let newLeft = rect.left, newTop = rect.top;
        const margin = 8;
        if (rect.right > winW - margin) newLeft = winW - rect.width - margin;
        if (rect.left < margin) newLeft = margin;
        if (rect.bottom > winH - margin) newTop = winH - rect.height - margin;
        if (rect.top < margin) newTop = margin;
        if (newLeft !== rect.left) bubble.style.left = newLeft + 'px';
        if (newTop !== rect.top) bubble.style.top = newTop + 'px';
        const side = (newLeft + rect.width / 2) < winW / 2 ? 'left' : 'right';
        if (side === 'left') bubble.style.right = 'auto';
        else bubble.style.left = 'auto';
        saveConfig({ bubbleTop: bubble.style.top, bubbleSide: side });
    }

    // ==================== 样式（含展开/收回动画关键帧） ====================
    const CSS = `
    <style>
        #st-cache-panel, #st-cache-bubble, .stc-summary, .stc-entry {
            transition: all 0.25s cubic-bezier(0.2, 0.9, 0.4, 1.1);
            will-change: transform, opacity;
        }
        #st-cache-panel {
            position: fixed;
            background: var(--stc-bg);
            backdrop-filter: blur(16px) saturate(180%);
            -webkit-backdrop-filter: blur(16px) saturate(180%);
            border: 1px solid var(--stc-border);
            border-radius: 18px;
            box-shadow: var(--stc-shadow), 0 0 0 1px rgba(255, 200, 210, 0.1) inset;
            z-index: 999999;
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Noto Sans', system-ui, sans-serif;
            display: flex;
            flex-direction: column;
            color: var(--stc-text);
            font-size: 13px;
            font-weight: 500;
            overflow: hidden;
            transform: translateZ(0);
            contain: layout style;
            width: ${savedConfig.panelWidth};
            height: ${savedConfig.panelHeight};
            resize: both;
            min-width: 280px;
            min-height: 320px;
            /* 展开/收回动画 */
            animation-duration: 0.35s;
            animation-fill-mode: forwards;
            animation-timing-function: cubic-bezier(0.34, 1.56, 0.64, 1);
        }
        @keyframes panel-expand {
            from { opacity: 0; transform: translateZ(0) scale(0.85); }
            to   { opacity: 1; transform: translateZ(0) scale(1); }
        }
        @keyframes panel-collapse {
            from { opacity: 1; transform: translateZ(0) scale(1); }
            to   { opacity: 0; transform: translateZ(0) scale(0.85); }
        }
        #st-cache-bubble {
            position: fixed;
            width: 56px;
            height: 56px;
            background: var(--stc-bg);
            backdrop-filter: blur(12px);
            -webkit-backdrop-filter: blur(12px);
            border: 1.8px solid var(--stc-accent);
            border-radius: 50%;
            box-shadow: 0 6px 18px rgba(0, 0, 0, 0.3), 0 0 0 3px rgba(255, 200, 210, 0.2);
            z-index: 1000000;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.3s cubic-bezier(0.18, 0.89, 0.32, 1.28);
            touch-action: none;
            transform: translateZ(0);
        }
        #st-cache-bubble:hover {
            transform: scale(1.08);
            border-color: #ffb7c5;
            box-shadow: 0 8px 24px rgba(255, 120, 140, 0.4);
        }
        .bubble-sakura-svg {
            width: 34px;
            height: 34px;
            filter: drop-shadow(0 2px 3px rgba(0,0,0,0.2));
            transition: transform 0.3s ease;
        }
        #st-cache-bubble:hover .bubble-sakura-svg {
            transform: rotate(10deg) scale(1.02);
        }
        .bubble-sakura-svg .petal-path { fill: var(--stc-accent); }
        .bubble-sakura-svg .center-circle { fill: #ff9eb0; }
        .stc-header {
            padding: 0 16px;
            height: 52px;
            background: var(--stc-bg-sec);
            border-bottom: 1px solid var(--stc-border);
            cursor: move;
            flex-shrink: 0;
            border-radius: 18px 18px 0 0;
            letter-spacing: 0.5px;
            font-weight: 600;
            backdrop-filter: blur(4px);
            display: flex;
            align-items: center;
            justify-content: space-between;
        }
        .stc-header span:first-child {
            background: linear-gradient(135deg, var(--stc-accent), #ffb7c5);
            -webkit-background-clip: text;
            background-clip: text;
            color: transparent;
            display: inline-flex;
            align-items: center;
            gap: 8px;
        }
        .stc-body {
            flex: 1;
            overflow-y: auto;
            background: transparent;
            padding: 10px 8px;
            scrollbar-width: thin;
        }
        .stc-body::-webkit-scrollbar { width: 5px; }
        .stc-body::-webkit-scrollbar-track { background: transparent; }
        .stc-body::-webkit-scrollbar-thumb { background: var(--stc-border); border-radius: 10px; }
        .stc-footer {
            display: flex;
            justify-content: flex-end;
            gap: 12px;
            padding: 12px 16px;
            background: var(--stc-bg-sec);
            border-top: 1px solid var(--stc-border);
            flex-shrink: 0;
            backdrop-filter: blur(4px);
        }
        .stc-btn-clear, .stc-btn-theme {
            padding: 6px 18px;
            border-radius: 40px;
            cursor: pointer;
            font-size: 12px;
            font-weight: 500;
            border: 1px solid var(--stc-border);
            background: var(--stc-bg);
            color: var(--stc-text);
            transition: all 0.2s;
            backdrop-filter: blur(4px);
            letter-spacing: 0.3px;
        }
        .stc-btn-clear:hover { background: var(--stc-danger); color: white; border-color: transparent; transform: scale(0.96); }
        .stc-btn-theme:hover { background: var(--stc-accent); color: white; border-color: var(--stc-accent); }
        .stc-entry {
            margin-bottom: 12px;
            background: rgba(255, 245, 247, 0.2);
            backdrop-filter: blur(8px);
            border-radius: 20px;
            border: 1px solid var(--stc-border);
            overflow: hidden;
            transition: all 0.2s;
        }
        .stc-summary {
            padding: 12px 16px;
            cursor: pointer;
            display: flex;
            justify-content: space-between;
            align-items: center;
            transition: background 0.2s;
            border-bottom: 3px solid transparent;
        }
        .stc-summary:hover { background: rgba(255, 200, 210, 0.25); }
        .stc-meta { display: flex; flex-direction: column; gap: 4px; overflow: hidden; flex: 1; }
        .stc-time { color: var(--stc-text-sec); font-size: 10px; font-weight: normal; letter-spacing: 0.3px; }
        .stc-detail { display: none; background: rgba(0,0,0,0.15); padding: 12px; border-top: 1px dashed var(--stc-border); font-size: 11px; }
        .stc-detail.open { display: block; }
        .stc-json { white-space: pre-wrap; word-break: break-all; font-family: monospace; color: var(--stc-text-sec); }
        .stc-progress {
            display: inline-block; width: 16px; height: 16px;
            border: 2px solid var(--stc-accent); border-top-color: transparent; border-radius: 50%;
            animation: stc-spin 0.8s linear infinite; margin-right: 8px;
        }
        @keyframes stc-spin { to { transform: rotate(360deg); } }
        .stc-hit-bottom { border-bottom: 3px solid var(--stc-hit-bottom) !important; box-shadow: 0 1px 0 var(--stc-hit-bottom); }
        .stc-miss-bottom { border-bottom: 3px solid var(--stc-miss-bottom) !important; box-shadow: 0 1px 0 var(--stc-miss-bottom); }
    </style>`;

    const HTML = `
    <div id="st-cache-panel" style="display:none;">
        <div class="stc-header" id="stc-drag-handle">
            <span>🌸 可待 · 缓存命中监测 🌸</span>
            <span style="font-size:11px; cursor:pointer;" id="stc-panel-close">✕</span>
        </div>
        <div class="stc-body" id="stc-cache-body"></div>
        <div class="stc-footer">
            <button class="stc-btn-clear" id="stc-clear">清理记录</button>
            <button class="stc-btn-theme" id="stc-theme-toggle" title="樱色流转">🌸切换🌸</button>
        </div>
    </div>
    <div id="st-cache-bubble" style="top: ${savedConfig.bubbleTop}; ${savedConfig.bubbleSide === 'right' ? 'right: 12px; left: auto;' : 'left: 12px; right: auto;'}"></div>
    `;

    function getSakuraSvg(size = 34) {
        return `<svg class="bubble-sakura-svg" viewBox="0 0 100 100" width="${size}" height="${size}">
            <g transform="translate(50,50)">
                <g class="petal-group">
                    <path class="petal-path" d="M0 0 C-15 -10 -20 -30 0 -45 C20 -30 15 -10 0 0 Z"/>
                    <path class="petal-path" d="M0 0 C-15 -10 -20 -30 0 -45 C20 -30 15 -10 0 0 Z" transform="rotate(72)"/>
                    <path class="petal-path" d="M0 0 C-15 -10 -20 -30 0 -45 C20 -30 15 -10 0 0 Z" transform="rotate(144)"/>
                    <path class="petal-path" d="M0 0 C-15 -10 -20 -30 0 -45 C20 -30 15 -10 0 0 Z" transform="rotate(216)"/>
                    <path class="petal-path" d="M0 0 C-15 -10 -20 -30 0 -45 C20 -30 15 -10 0 0 Z" transform="rotate(288)"/>
                </g>
                <circle class="center-circle" cx="0" cy="0" r="7"/>
            </g>
        </svg>`;
    }

    function createCompletedEntry(body, record) {
        const entry = topDoc.createElement('div');
        entry.className = 'stc-entry';
        const hit = record.hit, miss = record.miss, total = record.total, hitRate = record.hitRate;
        const fullData = record.fullData;
        const time = new Date(record.timestamp);
        const timeStr = `${time.getHours().toString().padStart(2,'0')}:${time.getMinutes().toString().padStart(2,'0')}:${time.getSeconds().toString().padStart(2,'0')}`;
        const hitStr = (hit != null) ? `<span style="color:var(--stc-hit);font-weight:bold;">✨ 命中: ${hit.toLocaleString()}</span>` : '命中: N/A';
        const missStr = (miss != null) ? `<span style="color:var(--stc-miss);font-weight:bold;">🍂 未中: ${miss.toLocaleString()}</span>` : '未命中: N/A';
        const totalStr = total > 0 ? `<span style="color:var(--stc-accent);">🌸 总计: ${total.toLocaleString()}</span>` : '';
        const bottomClass = (hitRate > 50) ? 'stc-hit-bottom' : 'stc-miss-bottom';
        const percentColor = (hitRate > 70) ? 'var(--stc-hit)' : (hitRate > 50 ? 'var(--stc-accent)' : 'var(--stc-miss)');
        const bgPercent = (hitRate > 50) ? 'rgba(255,100,120,0.25)' : 'rgba(255,140,66,0.25)';
        entry.innerHTML = `
            <div class="stc-summary ${bottomClass}">
                <div class="stc-meta">
                    <div style="white-space:nowrap;">${hitStr}</div>
                    <div style="white-space:nowrap;">${missStr}</div>
                    <div style="white-space:nowrap;margin-top:2px;">${totalStr}</div>
                </div>
                <div style="display:flex;align-items:center;gap:8px;">
                    <span style="color:${percentColor};font-size:13px;font-weight:bold;background:${bgPercent};padding:2px 10px;border-radius:40px;">${hitRate}%</span>
                    <span class="stc-time">${timeStr}</span>
                </div>
            </div>
            <div class="stc-detail">${fullData ? `<div class="stc-json">${JSON.stringify(fullData, null, 2)}</div>` : ''}</div>
        `;
        entry.querySelector('.stc-summary').onclick = () => entry.querySelector('.stc-detail').classList.toggle('open');
        body.appendChild(entry);
    }

    function applyTheme(themeName) {
        const theme = THEMES[themeName] || THEMES.light;
        const panel = topDoc.getElementById('st-cache-panel');
        const bubble = topDoc.getElementById('st-cache-bubble');
        const toggleBtn = topDoc.getElementById('stc-theme-toggle');
        if (panel) Object.entries(theme).forEach(([k,v]) => { if(k.startsWith('--')) panel.style.setProperty(k,v); });
        if (bubble) {
            Object.entries(theme).forEach(([k,v]) => { if(k.startsWith('--')) bubble.style.setProperty(k,v); });
            if (!bubble.querySelector('.bubble-sakura-svg')) bubble.innerHTML = getSakuraSvg(34);
        }
        if (toggleBtn) toggleBtn.innerText = theme.icon;
        saveConfig({ theme: themeName });
    }

    async function completeEntry(requestId, hit, miss, total, hitRate, fullData) {
        const body = topDoc.getElementById('stc-cache-body');
        const entry = body?.querySelector(`.stc-entry[data-request-id="${requestId}"]`);
        if (!entry) return;
        const time = new Date();
        const timeStr = `${time.getHours().toString().padStart(2,'0')}:${time.getMinutes().toString().padStart(2,'0')}:${time.getSeconds().toString().padStart(2,'0')}`;
        const hitStr = `<span style="color:var(--stc-hit);font-weight:bold;">✨ 命中: ${(hit||0).toLocaleString()}</span>`;
        const missStr = `<span style="color:var(--stc-miss);font-weight:bold;">🍂 未中: ${(miss||0).toLocaleString()}</span>`;
        const totalStr = total > 0 ? `<span style="color:var(--stc-accent);">🌸 总计: ${total.toLocaleString()}</span>` : '';
        const percentColor = (hitRate > 70) ? 'var(--stc-hit)' : (hitRate > 50 ? 'var(--stc-accent)' : 'var(--stc-miss)');
        const bgPercent = (hitRate > 50) ? 'rgba(255,100,120,0.25)' : 'rgba(255,140,66,0.25)';
        const bottomClass = (hitRate > 50) ? 'stc-hit-bottom' : 'stc-miss-bottom';
        const summary = entry.querySelector('.stc-summary');
        summary.className = `stc-summary ${bottomClass}`;
        summary.innerHTML = `
            <div class="stc-meta">
                <div style="white-space:nowrap;">${hitStr}</div>
                <div style="white-space:nowrap;">${missStr}</div>
                <div style="white-space:nowrap;margin-top:2px;">${totalStr}</div>
            </div>
            <div style="display:flex;align-items:center;gap:8px;">
                <span style="color:${percentColor};font-size:13px;font-weight:bold;background:${bgPercent};padding:2px 10px;border-radius:40px;">${hitRate}%</span>
                <span class="stc-time">${timeStr}</span>
            </div>`;
        const detail = entry.querySelector('.stc-detail');
        detail.innerHTML = `<div class="stc-json">${JSON.stringify(fullData, null, 2)}</div>`;
        summary.onclick = () => detail.classList.toggle('open');
        await saveToDB('cacheData', { requestId, hit, miss, total, hitRate, fullData, timestamp: Date.now() });
    }

    // ==================== 初始化 ====================
    async function init() {
        await initConfig();
        if (topDoc.getElementById('st-cache-panel')) return;
        topDoc.body.insertAdjacentHTML('beforeend', CSS + HTML);

        let panel = topDoc.getElementById('st-cache-panel');
        let bubble = topDoc.getElementById('st-cache-bubble');
        const bodyContainer = topDoc.getElementById('stc-cache-body');

        if (bubble) bubble.innerHTML = getSakuraSvg(34);
        applyTheme(savedConfig.theme || 'light');

        const records = await getAllFromDB('cacheData');
        if (records) records.sort((a,b) => b.timestamp - a.timestamp).slice(0,50).forEach(r => createCompletedEntry(bodyContainer, r));

        // ---------- 动画控制 ----------
        let animating = false;
        let dragMoved = false;
        let dragJustEnded = false;

        function resetBubbleSvg() {
            const svg = bubble?.querySelector('.bubble-sakura-svg');
            if (svg) {
                svg.style.transition = 'none';
                svg.style.transform = '';
                void svg.offsetHeight;
                svg.style.transition = '';
            }
        }

        function toggleState(force) {
            if (animating) return;
            const currentlyVisible = panel.style.display === 'flex';
            const show = (force !== undefined) ? !force : !currentlyVisible;
            if (show === currentlyVisible) return;

            animating = true;
            const onAnimationEnd = () => {
                panel.removeEventListener('animationend', onAnimationEnd);
                panel.style.animationName = '';
                if (!show) panel.style.display = 'none';
                resetBubbleSvg();
                saveConfig({ isMinimized: !show });
                animating = false;
            };

            if (show) {
                const bRect = bubble.getBoundingClientRect();
                let leftPos = (bRect.left < topWindow.innerWidth/2) ? (bRect.right + 12) : (bRect.left - panel.offsetWidth - 12);
                let topPos = bRect.top;
                if (topPos + panel.offsetHeight > topWindow.innerHeight - 10) topPos = topWindow.innerHeight - panel.offsetHeight - 10;
                if (topPos < 10) topPos = 10;
                if (leftPos + panel.offsetWidth > topWindow.innerWidth - 10) leftPos = topWindow.innerWidth - panel.offsetWidth - 10;
                if (leftPos < 10) leftPos = 10;
                panel.style.left = leftPos + 'px';
                panel.style.top = topPos + 'px';
                panel.style.display = 'flex';
                // 强制钳位，确保移动端不切割
                clampPanelToViewport(panel);
                panel.style.animationName = 'panel-expand';
                panel.addEventListener('animationend', onAnimationEnd, { once: true });
            } else {
                panel.style.animationName = 'panel-collapse';
                panel.addEventListener('animationend', onAnimationEnd, { once: true });
            }
        }

        if (!savedConfig.isMinimized) {
            setTimeout(() => toggleState(false), 100);
        }

        topDoc.getElementById('stc-panel-close').onclick = (e) => {
            e.stopPropagation();
            toggleState(true);
        };

        topWindow.addEventListener('resize', () => {
            clampBubbleToViewport(bubble);
            if (panel.style.display === 'flex') clampPanelToViewport(panel);
        });

        // ---------- 拖拽逻辑 ----------
        let isDragging = false, startX, startY, startLeft, startTop;
        const onDragStart = (e) => {
            isDragging = true;
            dragMoved = false;
            const clientX = e.touches ? e.touches[0].clientX : e.clientX;
            const clientY = e.touches ? e.touches[0].clientY : e.clientY;
            startX = clientX; startY = clientY;
            const rect = bubble.getBoundingClientRect();
            startLeft = rect.left; startTop = rect.top;
            bubble.style.transition = 'none';
            if (e.cancelable && !e.touches) e.preventDefault();
        };
        const onDragMove = (e) => {
            if (!isDragging) return;
            const clientX = e.touches ? e.touches[0].clientX : e.clientX;
            const clientY = e.touches ? e.touches[0].clientY : e.clientY;
            const dx = clientX - startX, dy = clientY - startY;
            if (Math.hypot(dx, dy) > 5) dragMoved = true;
            let newLeft = startLeft + dx, newTop = startTop + dy;
            const maxLeft = topWindow.innerWidth - bubble.offsetWidth - 8;
            const maxTop = topWindow.innerHeight - bubble.offsetHeight - 8;
            newLeft = Math.min(maxLeft, Math.max(8, newLeft));
            newTop = Math.min(maxTop, Math.max(8, newTop));
            bubble.style.left = newLeft + 'px';
            bubble.style.top = newTop + 'px';
            if (panel.style.display === 'flex') {
                let panelTop = newTop;
                if (panelTop + panel.offsetHeight > topWindow.innerHeight - 10) panelTop = topWindow.innerHeight - panel.offsetHeight - 10;
                if (panelTop < 10) panelTop = 10;
                panel.style.top = panelTop + 'px';
                clampPanelToViewport(panel);
            }
            if (e.cancelable) e.preventDefault();
        };
        const onDragEnd = () => {
            if (!isDragging) return;
            isDragging = false;
            bubble.style.transition = '';
            if (dragMoved) {
                clampBubbleToViewport(bubble);
                const side = (bubble.offsetLeft + bubble.offsetWidth/2) < topWindow.innerWidth/2 ? 'left' : 'right';
                if (side === 'left') bubble.style.right = 'auto';
                else bubble.style.left = 'auto';
                saveConfig({ bubbleTop: bubble.style.top, bubbleSide: side });
                dragJustEnded = true;
                setTimeout(() => { dragJustEnded = false; }, 150);
            }
            dragMoved = false;
        };

        bubble.addEventListener('mousedown', onDragStart);
        bubble.addEventListener('touchstart', onDragStart, { passive: false });
        topWindow.addEventListener('mousemove', onDragMove);
        topWindow.addEventListener('touchmove', onDragMove, { passive: false });
        topWindow.addEventListener('mouseup', onDragEnd);
        topWindow.addEventListener('touchend', onDragEnd);

        bubble.addEventListener('click', (e) => {
            if (dragJustEnded) return;
            if (!dragMoved) toggleState();
            dragMoved = false;
        });

        topDoc.getElementById('stc-clear').onclick = async () => {
            if (confirm('是否清理记录∠( ᐛ 」∠)_')) {
                bodyContainer.innerHTML = '';
                await clearStore('cacheData');
            }
        };

        topDoc.getElementById('stc-theme-toggle').onclick = () => {
            const nextTheme = savedConfig.theme === 'dark' ? 'light' : 'dark';
            applyTheme(nextTheme);
        };

        // ========== 拦截 fetch ==========
        if (!topWindow._st_cache_monitor_patched) {
            const rawFetch = topWindow.fetch;
            topWindow.fetch = async (...args) => {
                const url = typeof args[0] === 'string' ? args[0] : args[0]?.url || '';
                if (url.includes(TARGET_API)) {
                    const requestId = 'req_' + Date.now() + '_' + Math.random().toString(36).substr(2,6);
                    const entry = topDoc.createElement('div');
                    entry.className = 'stc-entry';
                    entry.setAttribute('data-request-id', requestId);
                    entry.innerHTML = `<div class="stc-summary"><div class="stc-meta"><span class="stc-progress"></span><span>🌸 花信生成中...</span></div></div><div class="stc-detail"></div>`;
                    bodyContainer.insertBefore(entry, bodyContainer.firstChild);
                    try {
                        const res = await rawFetch(...args);
                        const clone = res.clone();
                        clone.text().then(text => {
                            let lastData = null;
                            text.split('\n').forEach(l => {
                                if (l.startsWith('data: ') && l !== 'data: [DONE]') {
                                    try {
                                        const parsed = JSON.parse(l.substring(6));
                                        if (parsed.usage) lastData = parsed;
                                    } catch(e){}
                                }
                            });
                            if (lastData?.usage) {
                                const hit = lastData.usage.prompt_cache_hit_tokens || lastData.usage.prompt_tokens_details?.cached_tokens || 0;
                                const miss = lastData.usage.prompt_cache_miss_tokens || lastData.usage.prompt_tokens_details?.uncached_tokens || 0;
                                const total = hit + miss;
                                const hitRate = total > 0 ? parseFloat((hit/total*100).toFixed(1)) : 0;
                                completeEntry(requestId, hit, miss, total, hitRate, lastData);
                            } else {
                                completeEntry(requestId, 0,0,0,0, { error: "未获取到Usage数据" });
                            }
                        });
                        return res;
                    } catch(e) {
                        entry.remove();
                        throw e;
                    }
                }
                return rawFetch(...args);
            };
            topWindow._st_cache_monitor_patched = true;
        }
    }

    init().catch(e => console.error('[樱花监控器]', e));
})();
